+        width: usize,
+    ) -> DecoderState {
+        let cols: Vec<usize> = (start_col..start_col + width).collect();
+        let mut equations = Vec::with_capacity(width);
+        let mut rhs = Vec::with_capacity(width);
+
+        // Upper-triangular dense system:
